// components/HeroBanner.jsx
import { Link } from 'react-router-dom';
import { useBanner } from '../hooks/useBanner';

const HeroBanner = () => {
  const { data, isLoading, error } = useBanner();

  if (isLoading) {
    return (
      <div className="w-full h-96 bg-gray-200 animate-pulse flex items-center justify-center">
        <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="w-full h-96 bg-red-50 flex items-center justify-center">
        <p className="text-red-500">Impossible de charger la bannière</p>
      </div>
    );
  }

  return (
    <div 
      className="relative w-full h-[500px] md:h-[600px] bg-cover bg-center bg-no-repeat"
      style={{ backgroundImage: `url(${data?.imageUrl})` }}
    >
      {/* Overlay sombre pour améliorer la lisibilité du texte */}
      <div className="absolute inset-0 bg-black/40"></div>

      {/* Contenu */}
      <div className="relative z-10 flex flex-col items-center justify-center h-full text-center text-white px-4">
        <h1 className="text-4xl md:text-6xl font-bold mb-4">
          {data?.title || 'Nouvelle Collection'}
        </h1>
        <p className="text-lg md:text-xl mb-8 max-w-2xl">
          {data?.subtitle || 'Découvrez les tendances de la saison'}
        </p>
        <Link
          to="/products"
          className="bg-white text-gray-900 hover:bg-gray-100 font-semibold py-3 px-8 rounded-full transition duration-300 shadow-lg"
        >
          {data?.ctaText || 'Voir la collection'} →
        </Link>
      </div>
    </div>
  );
};

export default HeroBanner;
