// components/CategoriesGrid.jsx
import { Link } from 'react-router-dom';
import { useCategories } from '../hooks/useCategories';

const CategoriesGrid = () => {
  const { data: categories, isLoading, error } = useCategories();

  if (isLoading) {
    return (
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {[1, 2, 3, 4].map((i) => (
          <div key={i} className="bg-gray-200 rounded-xl h-32 animate-pulse"></div>
        ))}
      </div>
    );
  }

  if (error || !categories?.length) {
    return (
      <div className="text-center py-8 text-gray-500">
        ⚠️ Aucune catégorie disponible
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
      {categories.map((category) => (
        <Link
          key={category.id}
          to={`/products?category=${category.slug}`}
          className="group block bg-white rounded-xl shadow-md hover:shadow-xl transition-shadow duration-300 overflow-hidden"
        >
          <div className="h-40 bg-gradient-to-br from-indigo-100 to-blue-100 flex items-center justify-center">
            {category.icon ? (
              <img src={category.icon} alt={category.name} className="w-20 h-20 object-contain" />
            ) : (
              <span className="text-5xl">📁</span>
            )}
          </div>
          <div className="p-4 text-center">
            <h3 className="font-semibold text-gray-800 group-hover:text-indigo-600 transition">
              {category.name}
            </h3>
            <p className="text-sm text-gray-500 mt-1">
              {category.productCount || 0} produits
            </p>
          </div>
        </Link>
      ))}
    </div>
  );
};

export default CategoriesGrid;
